// 360Giving data.json is an array of publisher objects.
// Each publisher has a 'distribution' array with downloadURL entries.
// We only want JSON datasets (skip XLSX/CSV for simplicity).

const datasets = $input.first().json;

if (!Array.isArray(datasets)) {
  throw new Error('Unexpected 360Giving data format — expected array');
}

const urls = [];

for (const publisher of datasets) {
  const distributions = publisher.distribution || [];
  for (const dist of distributions) {
    if (
      dist.downloadURL &&
      (dist.mediaType === 'application/json' ||
       dist.downloadURL.endsWith('.json'))
    ) {
      urls.push({
        json: {
          url: dist.downloadURL,
          publisher: publisher.title || 'Unknown',
          publisherId: publisher.identifier || ''
        }
      });
    }
  }
}

console.log(`Found ${urls.length} JSON datasets to import`);
return urls;

// Parse a 360Giving JSON dataset into normalised grant rows
// for upsert into our 'grants' table.
//
// 360Giving grants have fields like:
//   id, title, description, currency, amountAwarded,
//   plannedDates.endDate, fundingOrganization[0].name
//
// We map them to our schema:
//   source_id, title, description, funder, max_award,
//   deadline, geographic_focus, is_active, url

const raw = $input.first().json;

// The dataset may be the array directly, or wrapped in a 'grants' key
let grants = [];
if (Array.isArray(raw)) {
  grants = raw;
} else if (raw && Array.isArray(raw.grants)) {
  grants = raw.grants;
} else {
  // Empty or unexpected format — skip
  return [];
}

const rows = [];

for (const g of grants) {
  try {
    const funder =
      (g.fundingOrganization && g.fundingOrganization[0]?.name) ||
      $('Loop Over Datasets').item.json.publisher ||
      'Unknown Funder';

    const deadline =
      (g.plannedDates && g.plannedDates[0]?.endDate) ||
      (g.plannedDates && g.plannedDates.endDate) ||
      null;

    const maxAward =
      typeof g.amountAwarded === 'number'
        ? g.amountAwarded
        : typeof g.amountAppliedFor === 'number'
        ? g.amountAppliedFor
        : null;

    if (!g.id || !g.title) continue;

    rows.push({
      json: {
        source_id:        g.id,
        title:            (g.title || '').substring(0, 255),
        description:      (g.description || '').substring(0, 2000),
        funder:           funder.substring(0, 255),
        max_award:        maxAward,
        currency:         g.currency || 'GBP',
        deadline:         deadline || null,
        geographic_focus: 'England',
        is_active:        deadline ? new Date(deadline) > new Date() : true,
        url:              g.dataSource || null,
        source:           '360giving'
      }
    });
  } catch (err) {
    // Skip malformed entries
  }
}

console.log(`Parsed ${rows.length} grants from dataset`);
return rows;

